module linear_voltage_regulator(  
    input [4:0] clamped_voltage,  
    output reg [4:0] actual_voltage  
);  
    always @(*) begin  
        if (clamped_voltage <= 5'b11111) begin  
            actual_voltage = clamped_voltage;  
        end else begin  
            actual_voltage = 5'b11111;  
        end  
    end  
endmodule
